INSERT INTO public.culture_traits (slug, description) VALUES ('builds-underground', 'Some structures are subterranean pits, dugouts, or tunnel entrances');
INSERT INTO public.culture_traits (slug, description) VALUES ('no-central-plaza', 'Culture doesn''t gather centrally; distributed or multi-node layout');
INSERT INTO public.culture_traits (slug, description) VALUES ('water-integrated', 'Canals, stilts, floating platforms, or amphibious access between buildings');
INSERT INTO public.culture_traits (slug, description) VALUES ('living-architecture', 'Buildings are grown organically (coral, resin, fungus), not constructed');
INSERT INTO public.culture_traits (slug, description) VALUES ('nomadic-core', 'Central structure is temporary (tent, yurt, pavilion); periphery may be permanent');
INSERT INTO public.culture_traits (slug, description) VALUES ('vertical-stacking', 'Builds upward — towers, elevated walkways, cliff-face nesting, bridges');
INSERT INTO public.culture_traits (slug, description) VALUES ('ruin-incorporators', 'Actively builds into or onto pre-existing ruins and salvaged structures');
INSERT INTO public.culture_traits (slug, description) VALUES ('symmetry-obsessed', 'Layouts are mirrored along one or two axes; strong geometric order');
INSERT INTO public.culture_traits (slug, description) VALUES ('chaos-builders', 'Intentionally irregular; no two buildings alike, organic sprawl');
INSERT INTO public.culture_traits (slug, description) VALUES ('communal-walls', 'Buildings share walls or form connected complexes rather than standing apart');
INSERT INTO public.culture_traits (slug, description) VALUES ('fortified-perimeter', 'Settlement has a defined defensive boundary — wall, ditch, palisade, or hedge');
INSERT INTO public.culture_traits (slug, description) VALUES ('elevated-construction', 'Buildings raised on stilts, platforms, or natural rock above ground level');
INSERT INTO public.culture_traits (slug, description) VALUES ('subterranean-preference', 'Most living space is below ground; surface structures are minimal');
INSERT INTO public.culture_traits (slug, description) VALUES ('secreted-structures', 'Buildings formed from biological secretion (resin, silk, chitin) not quarried material');
INSERT INTO public.culture_traits (slug, description) VALUES ('crystal-resonant', 'Structures incorporate or are built around crystal formations; layout follows crystal veins');
INSERT INTO public.culture_traits (slug, description) VALUES ('mechanical-integration', 'Settlement includes functional machinery, gears, pipes, or automata as infrastructure');
INSERT INTO public.culture_traits (slug, description) VALUES ('song-mapped', 'Layout follows acoustic or navigational-chant logic rather than visual geometry');
INSERT INTO public.culture_traits (slug, description) VALUES ('wind-oriented', 'Buildings and streets aligned to prevailing winds; windcatchers, sails, open corridors');
INSERT INTO public.culture_traits (slug, description) VALUES ('fire-centred', 'Central communal fire or forge is the social and spatial anchor, not a plaza');
INSERT INTO public.culture_traits (slug, description) VALUES ('seasonal-shift', 'Some structures are temporary or move with seasons; layout changes over the year');
INSERT INTO public.culture_traits (slug, description) VALUES ('bridges-between', 'Buildings connected by elevated walkways or bridges; ground level is secondary');
INSERT INTO public.culture_traits (slug, description) VALUES ('carved-not-built', 'Structures carved from existing rock, ice, or terrain rather than assembled');
INSERT INTO public.culture_traits (slug, description) VALUES ('flooded-intentionally', 'Parts of the settlement are deliberately underwater or waterlogged by design');
INSERT INTO public.culture_traits (slug, description) VALUES ('light-sensitive', 'Layout avoids or seeks sunlight deliberately — shade structures, reflectors, blackout walls');
INSERT INTO public.culture_traits (slug, description) VALUES ('scent-marked', 'Territory and building function communicated by scent, not signs — affects spacing and airflow');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('bergfolk', 'Bergfolk', 'Mountain hold-culture, runesmiths');
