INSERT INTO public.ancestries (slug, name, notes) VALUES ('markfolk', 'Markfolk', 'Farmers, dry-comedy, Dignity-mode');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('viddfolk', 'Viddfolk', 'Route-singers, high plains');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('steinfolk', 'Steinfolk', 'Stone-folk');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('pandor', 'Pandor', 'Panda-scholar archivists');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('deepwalkers', 'Deepwalkers', 'Coastal/cave Keepers');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('merfolk', 'Merfolk', 'Deep-water people (Djupvolk)');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('goblins', 'Goblins', 'Adaptive, in-band high-trust');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('fae', 'Fae', 'Layered, ancient, binding (Hollow Courts)');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('giants', 'Giants', 'Geological scale (the Seven)');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('dragons', 'Dragons', 'Territory, hoard, patience');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('everstill', 'Everstill', 'Vitstad archivists, preservation');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('constructs', 'Constructs', 'Made things; Bergfolk-built majority');
INSERT INTO public.ancestries (slug, name, notes) VALUES ('remnants', 'Remnants', 'Inscrutable ancients');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (0, 'Sea', 'Deep ocean and lake tiles. elev < 0.25 in terrain noise.', '#1a4f7a');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (1, 'Rocky Shore', 'Cold or moist coastline — rocky shingle. elev 0.25–0.30, (temp < 0.45 OR moist > 0.50).', '#8b6914');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (2, 'Sandy Shore', 'Warm dry coastline — sandy beach. elev 0.25–0.30, temp ≥ 0.45 AND moist ≤ 0.50.', '#e8c870');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (3, 'Marsh', 'Soggy bog in low-lying river valleys. elev 0.30–0.45 AND moist > 0.72.', '#4a7a3a');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (4, 'Dry Heath', 'Sandy/gravelly open heath. elev 0.30–0.62, moist ≤ 0.30.', '#b8904a');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (5, 'Coastal Heath', 'Light meadow / heather. elev 0.30–0.62, moist 0.30–0.60.', '#7a9a3a');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (6, 'Mixed Forest', 'Birch-spruce forest floor. elev 0.30–0.62, moist > 0.60.', '#2a7a2a');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (7, 'Dense Spruce', 'Warm high-elevation spruce stand. elev 0.62–0.78, temp > 0.50.', '#1a5a1a');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (8, 'Cold Granite', 'Cold high-elevation granite. elev 0.62–0.78, temp ≤ 0.50.', '#7a7a7a');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (9, 'Bare Rocky Summit', 'Warm bare summit rock. elev ≥ 0.78, temp ≥ 0.40.', '#9a9898');
INSERT INTO public.biomes (biome_index, name, description, base_color) VALUES (10, 'Snow Field', 'Cold icy summit. elev ≥ 0.78, temp < 0.40.', '#d8e8f8');
