INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-1', 'Bergfolk Stonework', 'stone', 'carved', 'rectilinear', 'subterranean', 'slit', 'functional', 'load-bearing', 'insulated', 'Massive carved stone blocks fitted without mortar. Halls carved into mountainsides with barrel-vaulted ceilings. Thick walls with narrow slit windows. Geometric precision — every edge squared, every surface dressed flat. Warmth comes from deep earth, not fire.', 'dwarven stonework, carved mountain hall, barrel vault, dressed stone blocks, slit windows, geometric, subterranean, no mortar, thick walls', 'Petra (Nabataean rock-cut city), Derinkuyu underground city (Cappadocia), Inca ashlar stonework');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-2', 'Runecarved Sanctuaries', 'stone', 'carved', 'fractal', 'subterranean', 'slit', 'elaborate', 'load-bearing', 'insulated', 'Sacred carved stone chambers deep underground. Every surface covered in interlocking rune patterns that repeat at multiple scales. Columns shaped like frozen roots. Light from bioluminescent lichen in carved channels. The geometry feels alive.', 'runic carvings, fractal patterns, sacred underground, bioluminescent, carved columns, interlocking runes, elaborate stonework, ritual chamber', 'Viking runestones + Hindu temple carvings (Khajuraho), Celtic knotwork, Newgrange passage tomb spirals');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-3', 'Lövfolk Living Architecture', 'living', 'grown', 'organic', 'canopy', 'open-air', 'moderate', 'living-support', 'ventilated', 'Buildings grown from living trees — branches guided over decades to form walls, floors, and roof canopy. Suspended in the canopy layer. Open-air gaps between woven branch walls let wind through. Moss and leaf cover instead of roofing. The building is still alive and growing.', 'treehouse, living wood, grown architecture, canopy dwelling, woven branches, moss roof, organic, elven, open-air, suspended', 'Ficus living root bridges (Meghalaya, India), Bali tree shrines, Tolkien-inspired Lothlórien');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-4', 'Canopy-weave', 'living', 'woven', 'organic', 'canopy', 'open-air', 'moderate', 'tensile', 'ventilated', 'Lightweight woven platforms and shelters strung between trees using living vine cordage. Flexible tensile structures that sway slightly in wind. Layered leaf-mat walls and floors. Connected by rope bridges. Everything can be relocated if a tree falls.', 'woven vine, rope bridge, hanging platform, tensile, canopy, leaf mat, flexible, lightweight, forest dwelling, swaying', 'Korowai treehouses (Papua New Guinea), Southeast Asian bamboo stilt villages, Amazonian malocas');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-5', 'Markfolk Timber-frame', 'wood', 'built', 'angular', 'on-ground', 'arch', 'minimal', 'post-and-beam', 'heated', 'Sturdy post-and-beam construction using heavy squared timbers with daub-filled panels between. Steep angular roofs with thick thatch or turf cover. Dark exposed beams contrast against pale lime-washed infill walls. Sits on stone footings at ground level. Smoke holes rather than chimneys on older buildings.', 'timber-frame, post-and-beam, dark beams, pale infill, steep thatch roof, angular, medieval Norse, wattle-and-daub, stone footings, smoke hole, iron hardware, functional, rustic', 'Norse/Viking timber longhouses, German Fachwerk half-timber, Anglo-Saxon mead halls');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-6', 'Longhouse Tradition', 'wood', 'built', 'angular', 'on-ground', 'arch', 'functional', 'post-and-beam', 'heated', 'Long rectangular halls with curved roof ridges and carved gable ends. Central hearth pit running the building''s length. Stave-built walls with external buttress posts. Animal-head carvings on ridge beams. Benches line the walls for sleeping and sitting. Double doors at each narrow end.', 'longhouse, Viking hall, curved ridge, carved gable, central hearth, stave walls, animal carvings, ridge beam, double doors, Norse, communal hall', 'Norwegian stave churches, Iroquois longhouses, Viking Age Trelleborg ring forts');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-7', 'Viddfolk Tent-craft', 'hide', 'woven', 'curved', 'on-ground', 'none', 'minimal', 'tensile', 'ventilated', 'Portable hide tents over flexible pole frames. Curved profiles that shed wind. Multiple layers — outer weatherproof hide, inner insulating felt. Smoke flap at apex. Packed earth or stone ring at base. Can be erected or struck in under an hour. Dyed geometric bands on the exterior.', 'hide tent, yurt, curved profile, pole frame, smoke flap, portable, nomadic, felt layers, geometric bands, wind-shedding, tundra', 'Sami lavvu, Mongolian ger/yurt, Inuit tupiq, Bedouin black tents');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-8', 'Wind-tower', 'stone', 'carved', 'angular', 'cliff-face', 'slit', 'functional', 'cantilever', 'ventilated', 'Narrow stone towers carved into and cantilevered from cliff faces. Vertical shafts channel wind for ventilation and cooling. Angled slit windows oriented to catch prevailing winds. Internal spiral stairs. The tower extends both into the cliff and outward over the drop.', 'cliff tower, cantilever, wind shaft, carved stone, vertical, narrow, slit windows, spiral stair, cliff-face, exposed, angular, wind-catching', 'Yemeni tower houses of Shibam, Persian badgir wind catchers, Tibetan cliff monasteries (Tiger''s Nest)');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-9', 'Steinfolk Ironwork', 'metal', 'built', 'rectilinear', 'on-ground', 'slit', 'functional', 'load-bearing', 'insulated', 'Heavy iron plate and rivet construction over stone cores. Dark oxidised metal cladding with visible rivet lines. Rectilinear geometry — no curves, no waste. Steam vents and pipe runs on exterior walls. Insulated with packed slag between double walls. Industrial and fortress-like.', 'iron plate, riveted, dark metal, industrial, steam vents, pipes, rectilinear, fortress, heavy, oxidised, slag insulation, steampunk-adjacent', 'Victorian ironwork (Crystal Palace), Meiji-era Japanese foundries, Art Deco industrial (Battersea Power Station)');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-10', 'Pandor Reed-and-Water', 'wood', 'built', 'curved', 'elevated', 'round', 'moderate', 'post-and-beam', 'ventilated', 'Stilted buildings over water or marshy ground. Curved reed-bundle walls on timber post frames. Round porthole-style windows. Thatched roofs with wide eaves for rain runoff. Walkways on elevated boardwalks between buildings. Everything slightly bowed from moisture.', 'stilt house, reed walls, round windows, elevated, boardwalk, marsh dwelling, curved, thatched, wide eaves, waterside, bamboo-like, tropical', 'Thai/Cambodian stilt houses, Uros reed islands (Lake Titicaca), Venetian pile foundations');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-11', 'Deepwalker Cave-dwelling', 'stone', 'carved', 'organic', 'subterranean', 'none', 'minimal', 'load-bearing', 'insulated', 'Natural caves expanded and smoothed by hand. Organic flowing shapes following the rock''s grain. No windows — light from phosphorescent fungus and oil lamps. Walls polished smooth where hands have touched for centuries. Doorways are rounded tunnels. Minimal intervention — the cave dictates the shape.', 'cave dwelling, carved cavern, organic shapes, no windows, phosphorescent, polished stone, tunnel doorway, underground, natural cave, minimal, dark', 'Cappadocian cave dwellings (Göreme), Sassi di Matera (Italy), Mesa Verde cliff dwellings');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-12', 'Merfolk Coral-growth', 'coral', 'grown', 'organic', 'floating', 'open-air', 'elaborate', 'living-support', 'submerged', 'Buildings grown from living coral over decades, guided by shapers. Organic branching forms in pinks, whites, and pale blues. Open-air — no distinction between wall and window, just openings in the coral matrix. Floats at or below waterline. Bioluminescent polyps provide light. Constantly growing and changing shape.', 'coral architecture, grown, organic, pink coral, bioluminescent, underwater, floating, open-air, branching, living building, elaborate, aquatic', 'Great Barrier Reef formations, Okinawan coral-stone walls, Maldivian coral-block mosques');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-13', 'Goblin Scrapwork', 'salvage', 'assembled', 'organic', 'on-ground', 'none', 'minimal', 'post-and-beam', 'ventilated', 'Chaotic assemblages of salvaged materials — scrap metal, broken timber, hide scraps, stolen doors. No two buildings alike. Walls lean at alarming angles held up by improvised bracing. Gaps everywhere (ventilation by accident). Built fast, rebuilt often. Surprisingly resilient.', 'scrapwork, junkyard, salvage, chaotic, leaning walls, improvised, patched, mismatched materials, goblin shanty, ramshackle, creative, ugly-functional', 'Brazilian favela improvisation, Kowloon Walled City, Mumbai dharavi recycling architecture');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-14', 'Fae Crystal Formation', 'crystal', 'cast', 'fractal', 'on-ground', 'lancet', 'excessive', 'shell', 'shaded', 'Crystalline structures that appear grown rather than built — cast from magical resonance. Faceted surfaces catch and scatter light in rainbow patterns. Tall lancet windows in impossibly thin walls. Fractal geometry at every scale. Semi-translucent — the interior glows. Excessive ornament that is also the structure.', 'crystal palace, faceted, rainbow light, lancet windows, fractal, translucent, magical, excessive ornament, thin walls, glowing, prismatic, ethereal', 'Gaudí''s Sagrada Família + Art Nouveau, Naica crystal caves (Mexico), Swarovski Kristallwelten');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-15', 'Giant Megaliths', 'stone', 'carved', 'rectilinear', 'on-ground', 'arch', 'minimal', 'load-bearing', 'heated', 'Enormous stone blocks stacked simply — each block taller than a human. Minimal joints, no mortar needed at this scale. Wide arched openings sized for giants. Interior spaces feel cavernous even for the builders. Everything oversized — steps, doors, hearths. Raw stone surfaces, undecorated.', 'megalithic, giant-scale, enormous stone blocks, oversized, wide arches, cavernous, raw stone, minimal, massive, primitive grandeur, cyclopean', 'Stonehenge, Baalbek trilithon (Lebanon), Easter Island ahu platforms, Mycenaean Lion Gate');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-16', 'Dragon Citadel-work', 'stone', 'built', 'rectilinear', 'on-ground', 'arch', 'elaborate', 'arch-and-vault', 'heated', 'Grand vaulted halls with massive pointed arches. Elaborate carved reliefs on every surface — battle scenes, genealogies, dragon motifs. Flying buttresses and towering spires. Heated by deep volcanic vents. Built to intimidate and endure millennia. Stone polished to a mirror finish.', 'dragon citadel, vaulted hall, pointed arch, flying buttress, spires, elaborate carvings, polished stone, grand, imposing, volcanic heat, dragon motifs, cathedral-scale', 'Gothic cathedrals (Chartres, Notre-Dame) + Chinese Forbidden City, Château de Chambord');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-17', 'Everstill Archive-halls', 'stone', 'built', 'rectilinear', 'on-ground', 'arch', 'moderate', 'arch-and-vault', 'insulated', 'Sober vaulted halls designed for preservation — climate-controlled through mass and geometry. Thick walls, deep arched windows with stone tracery. Moderate carved ornamentation — restrained but precise. Internal buttressed shelving walls. Every surface slightly cool to the touch. Built to last forever and look like it knows.', 'archive hall, library, vaulted ceiling, stone tracery, restrained ornament, climate-controlled, thick walls, scholarly, precise, timeless, institutional', 'Bodleian Library (Oxford), Strahov Monastery library (Prague), Diocletian''s Palace (Split)');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-18', 'Construct Purpose-built', 'metal', 'built', 'rectilinear', 'on-ground', 'slit', 'functional', 'load-bearing', 'insulated', 'Machine-precise metal structures built by constructs for constructs. Perfect right angles, uniform panel sizes, no aesthetic consideration. Slit openings for access rather than light (occupants don''t need it). Insulated against temperature extremes to protect mechanisms. Eerily clean and identical.', 'machine-built, metal panels, perfect geometry, uniform, no ornament, utilitarian, construct housing, clean, identical, mechanical, precise, alien-industrial', 'Brutalist concrete (Barbican), Soviet prefab housing, modernist factories (Bauhaus Dessau)');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-19', 'Remnant Ruin-shelters', 'salvage', 'assembled', 'organic', 'on-ground', 'slit', 'minimal', 'load-bearing', 'insulated', 'Earth-era ruins patched and made habitable with whatever is at hand. Concrete walls with hide curtains over gaps. Rebar poking through improvised timber extensions. Original slit windows still functional. Load-bearing walls respected even if not understood. A strange mix of ancient precision and desperate improvisation.', 'ruin shelter, post-apocalyptic, concrete ruins, patched, improvised, rebar, hide curtains, mixed materials, salvage, ancient and modern, desperate, survivor architecture', 'Post-war Berlin squats in ruins, Angkor Wat jungle reclamation, Roman ruins reused as medieval houses');
INSERT INTO public.architecture_styles (arch_id, name, primary_material, construction_method, form_language, ground_relation, window_style, ornament_level, structural_principle, climate_response, description, prompt_keywords, real_world_inspiration) VALUES ('ARCH-20', 'Wallborn Fortified Civic', 'stone', 'built', 'rectilinear', 'on-ground', 'arch', 'moderate', 'load-bearing', 'insulated', 'Defensive stone buildings that double as civic structures. Thick load-bearing walls with crenellations. Arched windows set deep in embrasures. Town halls that can serve as keeps. Market squares enclosed by walls. Moderate carved decoration — civic symbols, guild marks. Everything designed to be held if attacked.', 'fortified, civic stone, crenellations, embrasure windows, defensive, town hall keep, thick walls, guild marks, medieval fortress-town, dual-purpose, imposing but civic', 'Carcassonne (France), Dubrovnik (Croatia), Rhodes Old Town, Rothenburg ob der Tauber');
INSERT INTO public.fashion_styles (culture_id, real_world_fashion_inspiration, base_materials, base_palette, base_motifs) SELECT c.id, 'Faroese / Icelandic — knitted wool layers, oilskin slickers, practical wind-resistant silhouettes shaped by North Atlantic weather. Blended with fantasy coastal village tropes.', ARRAY['hand-knitted wool', 'oilskin', 'seal-leather', 'bone toggles'], ARRAY['slate-grey', 'sea-blue', 'off-white', 'storm-green'], ARRAY['wave-patterns', 'knotwork', 'fish-bone stitching'] FROM public.cultures c WHERE c.slug = 'coastborn';
INSERT INTO public.fashion_styles (culture_id, real_world_fashion_inspiration, base_materials, base_palette, base_motifs) SELECT c.id, 'Georgian / Caucasian highland — chokha coats, fitted waist with cartridge pockets, sheepskin cloaks (nabadi). Mixed with classic fantasy ranger and highland crofter aesthetics.', ARRAY['heavy wool', 'sheepskin', 'goat-leather', 'slate toggles'], ARRAY['charcoal', 'moss-green', 'russet', 'cream'], ARRAY['chevron stripes', 'mountain silhouettes', 'cross-stitch borders'] FROM public.cultures c WHERE c.slug = 'ridgefolk';
INSERT INTO public.fashion_styles (culture_id, real_world_fashion_inspiration, base_materials, base_palette, base_motifs) SELECT c.id, 'Korean hanbok-adjacent — clean wrapped lines, high waist ties, seasonal colour coding. Blended with classic fantasy peasant and harvest-village tropes.', ARRAY['linen', 'ramie cloth', 'straw', 'hemp cord'], ARRAY['wheat-gold', 'grass-green', 'sun-bleached white', 'clay-brown'], ARRAY['grain sheaves', 'sun-disc', 'plough-line borders'] FROM public.cultures c WHERE c.slug = 'fieldborn';
