INSERT INTO public.fashion_styles (culture_id, real_world_fashion_inspiration, base_materials, base_palette, base_motifs) SELECT c.id, 'Tibetan / Bhutanese — heavy wrapped chuba robes, yak-wool layers, felt boots, bold accent colours against earth tones. Blended with classic fantasy dwarf aesthetics — braided beards, rune-work, forge aprons.', ARRAY['yak-weight wool', 'treated leather', 'chainmail links', 'stone clasps'], ARRAY['iron-grey', 'amber', 'deep bronze', 'soot-black'], ARRAY['interlocking runes', 'hammer-and-anvil', 'geometric knotwork'] FROM public.cultures c WHERE c.slug = 'mountainhold';
