INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'layered-loose', 'none', 'wrapped hide boots with wool lining', ARRAY['rope belt', 'bone toggle clasps'], 'Thick knitted sweater under an oilskin slicker — Faroese layering logic. Trousers tucked into boots. Layers shed easily for work on boats. Sweater patterns are family-specific, like Icelandic lopapeysa.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'coastborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'layered-loose', 'wide-brimmed storm hat', 'tall leather boots', ARRAY['carved driftwood staff', 'embroidered collar'], 'Same layered silhouette but finer wool with more intricate knit patterns. Wave-pattern embroidery on collar and cuffs marks seniority. The storm hat is earned — only those who''ve weathered the worst wear one.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'coastborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'leather cap with cheek guards', 'reinforced sea-boots', ARRAY['shoulder harness', 'bone-studded bracers'], 'Shorter oilskin coat for mobility. Reinforced shoulders with layered hide. Muted colours — no embroidery, nothing to catch on rigging or give you away in fog.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'coastborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'driftwood-and-shell crown', 'barefoot', ARRAY['shell necklace', 'blue-dyed sash'], 'Blue-dyed linen reserved for tide ceremonies. Shell ornaments and kelp garlands. Always barefoot to touch the shore. The blue dye is woad-based — the dyeing itself is part of the rite.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'coastborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'fitted', 'tall sheepskin cap', 'hobnailed leather boots', ARRAY['broad leather belt with cartridge-style pouches', 'waist pouch'], 'Fitted coat cinched at the waist with a broad belt — chokha silhouette adapted to fantasy. Cartridge-pocket rows on the chest hold herb vials or fire-strikers. Sheepskin cap stays warm in ridgeline winds.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'ridgefolk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'layered-loose', 'tall papakha-style sheepskin hat', 'tall laced boots', ARRAY['walking staff', 'silver brooch at throat'], 'Darker-dyed coat with a sheepskin cloak (nabadi-style) over the shoulders. Silver throat brooch indicates community standing. The cloak doubles as a sleeping roll on the trail.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'ridgefolk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'iron half-helm', 'studded mountain boots', ARRAY['leather vambraces', 'belt axe loop'], 'Felted gambeson under a leather jerkin — the fitted coat stripped to its martial core. Minimal decoration, terrain-matched colours. Built to fight on slopes and scramble over ridges.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'ridgefolk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'draped', 'antler circlet', 'soft hide shoes', ARRAY['embroidered shoulder drape', 'carved bone pendant'], 'A wide embroidered shoulder drape in bright cream with mountain motifs — worn over the fitted coat. Reserved for solstice and ridge-moot gatherings. The antler circlet is carved from shed antlers, never hunted.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'ridgefolk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'wrapped', 'wide straw hat', 'simple leather sandals', ARRAY['high-waist sash tie', 'tool loop'], 'Clean-lined wrapped tunic tied at the high waist with a broad sash — hanbok-influenced silhouette in homespun linen. Straw hat is near-universal. Clothes are sun-bleached and patched freely — mending is no shame. Colour of the sash shifts by season.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'fieldborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'wrapped', 'clean straw hat with ribbon', 'soft leather shoes', ARRAY['embroidered apron', 'seed pouch'], 'Same wrapped silhouette but in finer ramie cloth, unpatched. A coloured ribbon on the hat and grain-sheaf embroidery on the apron signal respect. Elders wear muted earth tones — young fieldborn wear brighter seasonal colours.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'fieldborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'leather skullcap', 'wrapped leg bindings over boots', ARRAY['wooden shield slung on back', 'leather bracers'], 'Fieldborn militia, not professional soldiers. Hardened leather vest over work clothes, sash tucked tight. Still look like farmers at heart — because they are.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'fieldborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'wheat-wreath crown', 'barefoot', ARRAY['flower garlands', 'golden sash'], 'Harvest festival dress — flowing white linen gown with golden high-waist sash. Wheat wreaths and wildflower garlands. Barefoot on the earth. The most colour any fieldborn wears all year.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'fieldborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'fitted', 'cloth coif or cap', 'hard-soled leather shoes', ARRAY['leather belt with brass buckle'], 'Neat, structured tunic with clean lines — Byzantine-influenced layering without the excess. Everyone looks presentable. Civic pride runs deep — sloppy dress is a social offence inside the walls.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'wallborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'noble', 'fitted', 'velvet cap with brooch', 'polished high boots', ARRAY['gold chain of office', 'embroidered surcoat'], 'Rich brocade surcoat over fine linen — gold-thread embroidery at collar and cuffs, Byzantine style. Heraldic device on the chest. Rank is readable at a glance; that''s the point.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'wallborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'armoured', 'full helm with visor', 'armoured boots', ARRAY['tabard over mail', 'shield with heraldry'], 'City guard and garrison. Red-and-grey tabard over chain mail. The most uniformed look of any culture — matching is the point. Byzantine tagma discipline meets fantasy city watch.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'wallborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'circlet', 'embroidered slippers', ARRAY['ceremonial sash', 'tower-motif pendant'], 'Long formal robes with gold geometric borders — deliberately archaic, echoing an older imperial style. Worn at council sessions and city holidays. The more old-fashioned it looks, the more authority it carries.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'wallborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'wrapped', 'none', 'felted wool boots with iron soles', ARRAY['heavy belt with tool loops', 'stone bead bracelet'], 'Heavy wrapped coat over wool shirt — chuba-like silhouette cinched with a wide belt that doubles as tool storage. One shoulder often slipped free for forge work. Hair braided tight, beards clasped with stone rings. The wool is dense enough to stop sparks.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'mountainhold';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'artisan', 'wrapped', 'none', 'felted wool boots with iron soles', ARRAY['heavy leather apron', 'rune-stamped arm bands', 'tongs at hip'], 'The leather apron worn over the wrapped coat is the mark of craft rank — plain for apprentice, rune-stamped for master. Both shoulders slipped free at the forge; the coat bunches at the waist like a Tibetan work chuba.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'mountainhold';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'armoured', 'rune-etched helm', 'plate-reinforced boots', ARRAY['shield with clan rune', 'chainmail skirt'], 'Full chainmail over padded coat. Rune-etched helm unique to each clan. Heavy, immovable silhouette — Bergfolk fight like walls. The layering logic is the same as everyday dress, just armoured.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'mountainhold';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'draped', 'bronze circlet with amber inset', 'polished stone-clasped boots', ARRAY['clan chain across chest', 'ancestral rune tablet at hip'], 'Formal wrapped coat in deep amber and bronze, both shoulders covered. A dark cloth drape over one shoulder pinned with the clan chain. Reserved for oath-taking and ancestor rites in the deep halls. Closest the Bergfolk come to colour — amber against iron-grey.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'mountainhold';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'flowing', 'none', 'soft bark-sole slippers', ARRAY['vine belt', 'leaf-clasp at shoulder'], 'Long bark-cloth robe with bold geometric embroidery at hem and cuffs — Ainu attush influence. The fabric has an organic drape, nothing stiff. Colours shift subtly with the seasons as living-leaf dye fades. The embroidery patterns are believed to ward off corruption.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'sylvan-enclave';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'flowing', 'woven silver circlet', 'barefoot', ARRAY['staff wound with living vine', 'embroidered prayer band at wrist'], 'Elders dress simpler, not grander. Unadorned fabric but finer weave. The circlet is the only marker of age. A single embroidered prayer band on the wrist — the patterns are unique to each elder, never repeated.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'sylvan-enclave';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'bark half-mask', 'wrapped vine-sole boots', ARRAY['bark-plate chest guard', 'leaf-pattern camouflage cloak'], 'Tight-fitting silhouette for canopy movement. Bark armour grown to fit the wearer''s body. Camouflage cloak makes them near-invisible in forest. Geometric ward-embroidery concentrated around the heart.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'sylvan-enclave';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'flower crown (seasonal blooms)', 'barefoot', ARRAY['bioluminescent garlands', 'seed-pearl strands'], 'White bark-cloth gowns with the most elaborate embroidery — every edge bordered. Glow faintly at dusk. Worn for equinox gatherings. The flowers mark the specific rite — spring blossoms, autumn berries.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'sylvan-enclave';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'layered-loose', 'none or scrap-goggles pushed up', 'wrapped foot-rags or scavenged boots', ARRAY['oversized belt with dangling tools', 'pouch bandolier'], 'No two goblins dress alike. Clothes are a collage of found materials, traded scraps, and personal trophies. The messier, the more resourceful you look.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'bazaar-folk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'layered-loose', 'tall scrap-metal hat', 'mismatched boots', ARRAY['chain of keys and trinkets', 'painted face'], 'Elders pile on more layers and trophies. The tall hat is traditional — taller means you survived longer. Keys symbolise warrens they''ve overseen.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'bazaar-folk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'minimal', 'scrap-metal helm (improvised)', 'light wraps for speed', ARRAY['spiked shoulder pad (one side)', 'war-paint'], 'Strip down for speed. One spiked shoulder pad, war-paint in clan colours. Light and fast — goblin warriors don''t stand and fight, they ambush and scatter.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'bazaar-folk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'artisan', 'layered-loose', 'magnifying goggles', 'thick-soled scrap boots', ARRAY['leather apron covered in burn marks', 'wrist-mounted tool rack'], 'Goblin tinkers wear their workshop. Apron pockets bulge with gears and screws. Goggles are both tool and status — finer lenses mean better craft.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'bazaar-folk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'wrapped', 'conical reed hat', 'woven reed sandals', ARRAY['bamboo scroll case at hip', 'jade bead necklace'], 'Light cotton wrap tied with a broad sash — Bengali dhoti-influenced draping for ease in humid wetlands. Waterproofed at the hem for wading. Practical but always tidy — Pandor take pride in neatness even knee-deep in the marsh.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'waterstead';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'wrapped', 'formal lacquered hat', 'lacquered wooden sandals', ARRAY['ink-brush case', 'jade seal pendant'], 'Finer silk, darker colours. The jade seal pendant marks a keeper of records. Elders move slowly and dress deliberately — rushing is undignified.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'waterstead';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'lacquered bamboo helm', 'strapped waterproof boots', ARRAY['bamboo-plate cuirass', 'weighted net at hip'], 'Bamboo-lamellar armour — light and water-resistant. Designed to fight in and around water. Warriors carry nets as readily as blades.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'waterstead';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'lotus-flower headdress', 'barefoot', ARRAY['ink-brush calligraphy sash', 'paper lantern'], 'Cloud-white silk robes with hand-painted calligraphy along the hems. Each robe is unique — the text is a personal meditation. Worn for archive openings and water blessings.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'waterstead';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'minimal', 'none', 'barefoot or hide wraps', ARRAY['stone bead necklace', 'waist cord'], 'Giants wear little — a draped hide wrap like a shuka, a shoulder drape in cold weather. Clothing is secondary to ochre body paint and scarification for identity. Beaded stone necklaces mark lineage, Maasai-style.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'steading';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'draped', 'antler-and-bone crown', 'barefoot', ARRAY['carved boulder pendant on chain', 'ritual body paint'], 'A great drape of layered hides over both shoulders. The antler crown is ancient — passed down, not made new. Elders move like the landscape.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'steading';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'minimal', 'none', 'barefoot', ARRAY['war-paint across chest and face', 'bone arm bands'], 'Warriors strip down and paint up. Each pattern tells a battle. No armour — giant hide is armour enough. Bone bands on the upper arms mark kills.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'steading';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'draped', 'stone mask', 'barefoot', ARRAY['full body paint in white clay', 'stone chime belt'], 'Stone masks carved to resemble ancestor faces. Full white clay body paint. Stone chimes at the waist ring with each step. Reserved for the Seven''s gathering rites.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'steading';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'fitted', 'none', 'clawed boots', ARRAY['scale-patterned arm wraps', 'obsidian collar pin'], 'Fitted garments that echo draconic proportions — high Safavid-style collar, tapered sleeves, sharp silhouette. Scale patterns are woven into the brocade, Persian-style. Even common dress carries an imperial weight.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'dragonkin-remnant';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'noble', 'flowing', 'horned diadem', 'gilded boots', ARRAY['floor-length cape', 'gold eye-motif brooch'], 'The cape is everything — it mimics folded wings. Crimson and gold brocade, floor-length, lined with black — Safavid court excess filtered through draconic grandeur. The horned diadem recalls ancient dragon crowns.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'dragonkin-remnant';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'armoured', 'dragon-skull helm (stylised)', 'taloned greaves', ARRAY['scale-plate cuirass', 'tail-like back banner'], 'Armour designed to evoke the dragon form — ridged pauldrons, a back banner that suggests a tail. Intimidation is half the battle.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'dragonkin-remnant';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'full dragon mask', 'barefoot on heated stone', ARRAY['flame-tongue embroidered stole', 'incense censer on chain'], 'Full dragon mask of lacquered obsidian. Smoke-purple robes with flame-tongue hems. Ceremonies take place on heated stone floors — barefoot to prove endurance.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'dragonkin-remnant';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'wrapped', 'wrapped headscarf', 'soft leather riding boots', ARRAY['coin-fringed sash', 'waterskin strap'], 'Practical layers that protect from sun and sand. Headscarf doubles as dust mask. Bright colours — caravans want to be seen on the road, not hidden.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'caravan-folk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'wrapped', 'tall embroidered turban', 'embroidered slippers', ARRAY['star-map pendant', 'story-beads on wrist'], 'The turban''s height and embroidery tell how many routes you''ve mastered. Story-beads — each bead is a journey completed. Elders sit and trade in beads.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'caravan-folk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'chainmail coif under headscarf', 'hard-soled riding boots', ARRAY['curved scimitar sash', 'leather vambraces'], 'Outriders and caravan guards. Fitted for the saddle, loose enough to swing. Chainmail hidden under the headscarf — don''t advertise your readiness.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'caravan-folk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'jewelled headband', 'barefoot on woven rug', ARRAY['full coin-fringe vest', 'incense pouch'], 'Market festival dress — every coin you''ve earned displayed as fringe. Saffron and indigo silk. Ceremonies happen on spread rugs — the caravan carries its own sacred ground.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'caravan-folk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'minimal', 'none', 'barefoot', ARRAY['coral bead strands across chest', 'shell arm bands'], 'Merfolk dress for water — minimal coverage, nothing that drags. Kelp wraps at the hips like a Samoan lavalava, coral beads for identity. Tattoo patterns (pe''a-influenced) are as important as clothing — iridescent ink marks lineage and rank.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'reefborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'draped', 'pearl-strand headdress', 'barefoot', ARRAY['abalone pectoral', 'bioluminescent ink tattoos'], 'Elders wear more — a kelp-and-shell drape over the shoulders. Pearl strands mark age. Bioluminescent tattoos glow in deep water for recognition.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'reefborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'shell-plate helm', 'barefoot', ARRAY['shell-plate chest guard', 'spine-tipped gauntlets'], 'Shell-plate armour strapped tight — can''t snag on coral. Spine tips on gauntlets double as weapons. Streamlined for combat in currents.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'reefborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'living coral crown', 'barefoot', ARRAY['sea-silk train', 'bioluminescent body paint'], 'Sea-silk robes that billow like jellyfish in the current. Living coral crown cultivated over years. Worn for reef-song rituals in the deep trenches.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'reefborn';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'wrapped', 'fur-edged felt cap', 'tall riding boots', ARRAY['wide sash belt', 'riding crop loop'], 'Wrapped chapan-style coat tied with a broad embroidered sash. Everything designed for the saddle. Telpek-style felt cap stays on in wind. Colours mark family group — everyone in camp can tell kin at a distance.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'steppe-camp';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'wrapped', 'tall ceremonial hat with eagle feather', 'embroidered boots', ARRAY['silver horse-head belt buckle', 'bone prayer beads'], 'Richly embroidered deel in deeper colours. The eagle feather on the hat is earned, not decorative — one feather per route mastered.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'steppe-camp';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'leather and iron helm', 'armoured riding boots', ARRAY['quiver harness', 'horsehide lamellar vest'], 'Horsehide lamellar over padded deel. Quiver always on the back. Light enough to ride, tough enough to take an arrow. Wind-spiral painted on the helm.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'steppe-camp';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'sky-blue felt crown', 'white leather boots', ARRAY['eagle bone whistle on cord', 'embroidered story-belt'], 'White and sky-blue robes for sky-song ceremonies. The story-belt has a panel for each generation. Eagle bone whistle calls the wind for blessing.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'steppe-camp';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'fitted', 'chullo-style ear-flap cap with wind-goggles', 'grip-soled climbing boots', ARRAY['harness with carabiner loops', 'feather token at collar'], 'Fitted waxed poncho-layer over tight base — Andean altitude logic. Nothing loose to catch the wind at height. Harness is everyday wear, not just for climbing — the eyries demand it. Chullo-style ear-flap caps with feather tokens.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'windfarer-eyrie';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'fitted', 'feathered cap with wind-vane', 'fur-lined climbing boots', ARRAY['wind-reader pendants (tiny chimes)', 'fur-lined collar'], 'Same tight fit but with fur lining for warmth. Wind-reader chimes at the breast — they read gusts by sound. The feathered cap marks a master of heights.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'windfarer-eyrie';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'raptor-skull helm', 'taloned climbing boots', ARRAY['glider-cloak folded at back', 'throwing harness'], 'Glider-cloaks that spread for controlled descents — part clothing, part equipment. Raptor-skull helm for intimidation. Attack from above, always.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'windfarer-eyrie';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'draped', 'full feather headdress', 'barefoot on stone', ARRAY['feather cape spread wide', 'wind-chime belt'], 'The feather cape spread out like wings — each feather is gifted by a different eyrie member. Wind-chime belt sings in the updraft. Ceremonies held at the highest point, open to the sky.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'windfarer-eyrie';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'layered-loose', 'none', 'barefoot', ARRAY['root-fibre wrist wraps', 'seed pouch'], 'Clothes that look half-grown. Moss-cloth tunics that blur the line between garment and undergrowth — Yanomami-level integration with the forest. Body paint in spore-dot patterns is as important as clothing. Always barefoot to feel the forest floor.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'grovekin';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'layered-loose', 'living moss crown', 'barefoot', ARRAY['mycelium-thread shawl', 'glowing spore lantern'], 'The moss crown actually grows on the elder — watered and tended. Mycelium-thread shawl connects them symbolically to the grove network. Spore lantern for underground gatherings.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'grovekin';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'bark helm with thorn crest', 'root-sole wraps', ARRAY['thorn-spine armour', 'pollen-bomb pouch'], 'Thorn-spine armour grown on hardwood frames. Pollen bombs for disorientation. Grove warriors defend by making the forest itself hostile — their gear blends in completely.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'grovekin';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'bioluminescent mushroom crown', 'barefoot', ARRAY['spore-dust body paint', 'root-fibre prayer cords'], 'Bioluminescent mushroom crowns that glow blue-green in the dark. Ceremonies happen underground at night. Spore-dust body paint makes everyone glow faintly.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'grovekin';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'fitted', 'brass-rimmed goggles (on forehead or around neck)', 'steel-toed boots', ARRAY['heavy tool belt', 'measurement tape looped at hip'], 'Practical workwear that doubles as everyday clothes — no real distinction, like Edo-period artisans who lived in their workshops. Canvas coveralls or fitted jacket and trousers. Always oil-stained. Goggles are identity — guild rank is read from the lens quality.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'workshop-collective';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'artisan', 'fitted', 'precision goggles with multiple lenses', 'steel-toed boots', ARRAY['master''s leather apron with brass guild badge', 'wrist-mounted calipers'], 'The guild badge on the apron tells everything — craft, rank, speciality. Multi-lens goggles for detail work. Master artisans are the aristocracy here.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'workshop-collective';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'armoured', 'riveted helm with face-plate', 'pneumatic-soled boots', ARRAY['brass-plated cuirass', 'mechanical gauntlet'], 'Construct-inspired armour — brass plating over canvas padding. Mechanical gauntlets with enhanced grip. Workshop warriors look like walking machines.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'workshop-collective';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'fitted', 'polished brass crown with clock face', 'polished leather boots', ARRAY['ceremonial master-key on chain', 'clean white canvas coat'], 'The only time workshop folk wear clean clothes. White canvas coat, polished brass — the clock-face crown marks the turning of a new project cycle. The master-key opens the Great Workshop.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'workshop-collective';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'flowing', 'none', 'barefoot or crystal-soled sandals', ARRAY['resonance crystal pendant', 'gossamer arm drapes'], 'Gossamer wraps draped Tuareg-style — the crystal thread refracts light like indigo dye shifts in sun. Geometric silver crystal-clasps at shoulder and hip. No two garments look the same in different light. Unsettling to outsiders, like Tuareg blue-stained skin but with prismatic light.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'crystal-resonance';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'flowing', 'crystal tiara that hums faintly', 'barefoot', ARRAY['harmonic tuning fork at hip', 'layered crystal shard necklace'], 'The tiara resonates with the elder''s voice — it hums when they speak truth. Layered crystal shards click and chime with movement. Fae elders sound like wind chimes.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'crystal-resonance';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'crystal-shard helm', 'crystal-soled greaves', ARRAY['resonance blade harness', 'shard-embedded bracers'], 'Crystal shards embedded in armour — they ring on impact, disorienting opponents with harmonic feedback. The sound of a Fae warrior approaching is the warning itself.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'crystal-resonance';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'full prismatic crown', 'barefoot', ARRAY['light-woven cape that glows', 'resonance staff'], 'Full prismatic regalia — the crown splits light into rainbows. Light-woven cape actually emits soft light. Ceremonies are visual symphonies, impossible to describe to non-Fae.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'crystal-resonance';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'layered-loose', 'deep hood', 'wrapped boots sealed against dust', ARRAY['memory shard pouch', 'breathing mask (lowered when safe)'], 'Layers of salvaged fabric wrapped shamma-style, patched but never discarded. Hoods always available — Remnants prefer shadow, like Coptic monks withdrawing from the world. Breathing masks for venturing into unstable ruins. The visible repairs are intentional — each patch is a small history, a record kept in cloth.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'refuge-keepers';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'layered-loose', 'inscribed metal half-mask', 'sealed boots', ARRAY['archive glyph tattoos on hands', 'memory shard chain'], 'The metal half-mask is inscribed with archive glyphs — it''s both identity and rank. Memory shard chain holds fragments of pre-collapse knowledge. Elders are living libraries.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'refuge-keepers';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'armoured', 'full salvaged helm', 'reinforced sealed boots', ARRAY['scrap-plate armour', 'ruin-charge grenades on belt'], 'Heavy salvaged armour — mismatched plates bolted together. Function over aesthetics. Refuge warriors guard the perimeter against corruption and scavengers.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'refuge-keepers';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'draped', 'full mask — featureless, ash-white', 'barefoot', ARRAY['ash-white shroud', 'memory shard held in both hands'], 'Full featureless white mask and shroud — Ethiopian timkat-procession stillness. Identity dissolved into the collective memory. Memory shards held aloft during remembrance rites. Silence is the ceremony.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'refuge-keepers';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'layered-loose', 'rolled bandana', 'rope-soled deck shoes', ARRAY['rope belt', 'shell-button vest'], 'Loose linen shirt with open collar, vest with shell buttons, rolled trousers — Greek island fisherman meets fantasy dockworker. Everything salt-faded and soft from washing. Bandana keeps hair out of rigging. Relaxed and sun-worn — harbor folk don''t dress to impress.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'harborfolk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'layered-loose', 'captain''s wide-brim hat', 'tall sea boots', ARRAY['spyglass on cord', 'tide-chart scarf'], 'The captain''s hat doesn''t mean ship captain — it''s a harbor elder''s mark. Tide-chart scarf printed with local currents. Spyglass is ceremonial now but always carried.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'harborfolk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'fitted', 'leather skullcap', 'grip-soled boarding boots', ARRAY['cutlass baldric', 'boarding hook on belt'], 'Harbor guard and anti-piracy patrol. Fitted for climbing and boarding. Cutlass and hook — weapons that work in tight ship corridors. No armour — it drowns you.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'harborfolk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'coral-and-shell crown', 'barefoot on dock planks', ARRAY['net-weave shawl', 'lantern on pole'], 'Tide festival dress — white flowing robes, barefoot on the docks. Net-weave shawl symbolises the catch. Lanterns lit at dusk and floated out to sea for the lost.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'harborfolk';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'fitted', 'none or cloth wrap under work helm', 'iron-plated boots', ARRAY['chain-link belt', 'slag-glass eye shield'], 'Steinfolk dress like they never left the forge. Oil-treated canvas over thick undergarments. Iron plating on boots and shoulders is everyday wear — the weight is nothing to stone-folk.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'ironborne-encampment';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'artisan', 'fitted', 'full-face forge visor', 'iron-plated boots', ARRAY['master-smith''s apron (asbestos-weave)', 'tong holster', 'crucible-mark brand on forearm'], 'The crucible brand is earned — literally branded when you pour your first independent melt. Forge visor never comes off during work. The apron has survived more heat than most buildings.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'ironborne-encampment';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'armoured', 'full iron helm with chain drape', 'iron greaves', ARRAY['full chain hauberk', 'iron-banded tower shield'], 'Walking fortresses. Full iron — helm, chain, plate, greaves. Steinfolk warriors don''t dodge; they absorb. The chain drape from the helm protects the neck and looks like a metal beard.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'ironborne-encampment';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'fitted', 'polished iron crown with forge-light inset', 'polished iron boots', ARRAY['chain-of-office with crucible pendant', 'ceremonial hammer'], 'Same silhouette as everyday — Steinfolk don''t do flowing robes. Instead, everything is polished mirror-bright. The forge-light inset in the crown glows orange. The ceremonial hammer has never struck metal.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'ironborne-encampment';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'common', 'fitted', 'none — hair woven with thorns and leaves', 'barefoot', ARRAY['thorn bracelet', 'spider-silk pouch'], 'Tight-fitting clothes for moving through dense undergrowth — Dayak jungle logic. Thorn-woven fibre is naturally barbed on the outside, like rattan armour that discourages grabbing. Intricate beadwork at wrists and throat. Hair is part of the outfit — woven with the thicket itself.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'thicket-dwellers';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'elder', 'layered-loose', 'thorn-and-web veil', 'barefoot', ARRAY['web-pattern face paint', 'lichen-dyed shawl'], 'Elders slow down and dress in layers — they sit in the thicket''s heart and the thicket grows around them. The thorn-and-web veil is half-natural, half-made. Web face paint marks the weaver-speakers.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'thicket-dwellers';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'warrior', 'minimal', 'thorn-spike crest (grown into hair)', 'barefoot', ARRAY['thorn-gauntlets', 'insect-swarm gourd'], 'Almost invisible in the thicket. Thorn spikes grown directly into braided hair. Thorn-gauntlets for close combat. The insect-swarm gourd releases stinging clouds — thicket warfare is nasty.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'thicket-dwellers';
INSERT INTO public.fashion_variants (fashion_style_id, role, silhouette, headwear, footwear, accessories, notes) SELECT fs.id, 'ceremonial', 'flowing', 'living flower crown with bioluminescent moths', 'barefoot', ARRAY['spider-silk robe that catches moonlight', 'thorn-spiral body paint'], 'Spider-silk robes shimmer in moonlight like dew-covered webs. Living moths perch on the flower crown, wings glowing. Ceremonies happen at midnight in the deepest thicket — outsiders are never invited.' FROM public.fashion_styles fs JOIN public.cultures c ON c.id = fs.culture_id WHERE c.slug = 'thicket-dwellers';
